module quick_sort(input [15:0] data_in, output reg [15:0] data_out);  
    reg [7:0] unsorted_data [1:0];  
    integer i, j;  
    always @(*) begin  
        unsorted_data[0] = data_in[15:8];  
        unsorted_data[1] = data_in[7:0];  

        // Simple Bubble Sort for 2 elements  
        for (i = 0; i < 1; i = i + 1) begin  
            for (j = 0; j < 1 - i; j = j + 1) begin  
                if (unsorted_data[j] > unsorted_data[j + 1]) begin  
                    // Swap  
                    {unsorted_data[j], unsorted_data[j + 1]} = {unsorted_data[j + 1], unsorted_data[j]};  
                end  
            end  
        end  

        data_out = {unsorted_data[0], unsorted_data[1]};  
    end  
endmodule
